SELECT COUNT(1) AS QUANTIDADE FROM LATTES_ORIENTACAO LO JOIN SERVIDOR S ON S.PK_SIAPE = LO.FK_SIAPE WHERE S.SIGLA_CAMPUS = 'ITU' AND S.GENERO = 'MASCULINO' AND LO.ANO >= (CAST(strftime('%Y', 'now') AS INTEGER) - 4) AND LOWER(COALESCE(S.AREA_INGRESSO, '')) LIKE '%sociologia%' AND LOWER(LO.TIPO) LIKE LOWER('%iniciacao%')